INSERT INTO insurance_plans (plan_name, plan_description) VALUES
    ('Basic Protection', 'Podstawowe ubezpieczenie obejmujące drobne urazy oraz pierwszą pomoc medyczną na terenie parku.'),
    ('Double Protection', 'Ubezpieczenie obejmujące koszty leczenia w razie wypadków na atrakcjach oraz transport medyczny.'),
    ('Double + Food', 'Ubezpieczenie standardowe rozszerzone o rekompensatę w razie straty, kradzieży lub niezadowolenia z jedzenia zakupionego na terenie parku.'),
    ('VIP Full Coverage', 'Pełna ochrona ubezpieczeniowa obejmująca leczenie, hospitalizację oraz rekompensaty finansowe w razie poważnych wypadków. Ubezpieczenie obejmuje również straty materialne spowodowane przez obiekty, pracowników lub gości znajdujących się na terenie parku. Ochrona typu "Food" jest wliczona w cenę.'),
    ('VR Protection', 'Ubezpieczenie obejmuje koszty urazów fizycznych oraz zniszczeń mienia powstałych w wyniku reakcji organizmu na doświadczenia oferowane na atrakcjach dostępnych przez wirtualną rzeczywistość (VR).');
